import{_ as i,c as l,o as e,ak as t}from"./chunks/framework.CYxz2ou1.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoLife/A-书架/1-读书笔记/202301-皮囊.md","filePath":"NanoLife/A-书架/1-读书笔记/202301-皮囊.md","lastUpdated":1775467143000}'),r={name:"NanoLife/A-书架/1-读书笔记/202301-皮囊.md"};function o(n,a,s,_,d,c){return e(),l("div",null,[...a[0]||(a[0]=[t('<h2 id="📘-基本信息" tabindex="-1">📘 基本信息 <a class="header-anchor" href="#📘-基本信息" aria-label="Permalink to &quot;📘 基本信息&quot;">​</a></h2><ul><li>📘 <strong>书名：皮囊</strong></li><li>🕵️‍♂️ <strong>作者</strong>：蔡崇达</li><li>🥂 <strong>推荐分数</strong>：9</li><li>⏰ <strong>阅读时间</strong>：2023 年 1 月</li></ul><p>![[Pasted image 20260405150629.png|206]]</p><h2 id="📝-总结" tabindex="-1">📝 总结 <a class="header-anchor" href="#📝-总结" aria-label="Permalink to &quot;📝 总结&quot;">​</a></h2><p>飞机上看的，挺好看的，有点类似轻小说。后面有个改编的电影，叫《浪浪人生》。</p><h2 id="📖-摘录" tabindex="-1">📖 摘录 <a class="header-anchor" href="#📖-摘录" aria-label="Permalink to &quot;📖 摘录&quot;">​</a></h2><ul><li>我们的生命本来多轻盈，都是被这肉体和各种欲望的浑浊给拖住。肉体是拿来用的，不是拿来伺候的。</li><li>这是对路过生命的所有人最好的尊重，这也是和时间抗衡，试图挽留住每个人唯一可行的努力。还是理解自己最好的方式——路过我们生命的每个人，都参与了我们，并最终构成了我们本身。</li><li>天降姿色命中定，心善面丑相由命。</li><li>路过我们生命的每个人，都参与了我们，并最终构成了我们本身。</li><li>我知道那种舒服，我认识这里的每块石头，这里的每块石头也认识我; 我知道这里的每个角落，怎么被岁月堆积成现在的光影，这里的每个角落也知道我，如何被时间滋长出这样的模样。---关于故乡</li><li>我，或许许多多人，都在不知道如何生活的情况下，往往采用最容易掩饰或者最常用的借口--理想或者责任。</li><li>我常对朋友说，理解是对他人最大的善举。当你坐在一个人面前，听他开口说话，看得到各种复杂，精密的境况和命运，如何最终雕刻出这样的性格，思想，做法，长相，这才是理解。而有了这样的眼镜，你才算真正“看见”那个人，也才会发觉，这世界最美的风景，是一个个活出各自模样和体系的人。</li><li>我基本不太想太长远的事情，很多事情想大了会压得自己难受。我只想着做好一点点的事情，然后期待，这么一点点事，或许哪天能积累成一个不错的景观。起码是自己的景观。</li><li>最离奇的理想所需要的建筑素材就是一个个庸常而枯燥的努力。</li><li>生活就是张这样的问卷，你没有回答，它会一直追问下去，而且你不回答这个问题，就永远看不到下一个问题。</li><li>你需要它为你整理一天的思绪，你需要跟随它一起回到家乡，你需要让你的心醒着，需要将皮囊全部照亮。</li></ul>',7)])])}const u=i(r,[["render",o]]);export{p as __pageData,u as default};
